-- Repartidor de misiones
lang["#MISSION_GIVER_CROWMAN"] = "Joe el Cuervo"
lang["#MISSION_GIVER_CROWMAN_SUBTITLE"] = "Sal de la tierra, insolaciГіn del cerebro."
lang["#MISSION_GIVER_CROWMAN_GREET_0"] = "ВЎTГә, mocoso! ВЎVen aquГӯ! ВЎLos cuervos estГЎn otra vez, planeando robar mi maГӯz! ВЎLos oigo venir ahora mismo!"

-- Misiones
lang["#MISSION_CROWMAN_SINGLESHOTGUN"] = "Todos Empiezan en AlgГәn Lado"
lang["#MISSION_CROWMAN_SINGLESHOTGUN_DESC"] = "ВЎTГә, mocoso! ВҝVienes a robarme el maГӯz? ВҝNo? Debes haberte escapado del pueblo mientras tus padres estaban distraГӯdos. Apuesto a que un mocoso bizco como tГә no podrГӯa darle a un cuervo aunque se le posara en la nariz. ВЎUn mocoso como tГә necesita que le enseГұen los principios! ВЎConsГӯguete un cuervo usando una vieja Escopeta de un Solo CaГұГіn, Y NADA MГҒS! ВЎLO SABRГү! Los parientes de Nimrod me enseГұaron a rastrear a un mentiroso por el olfato."
lang["#MISSION_CROWMAN_SINGLESHOTGUN_HINT"] = "Adquiere una Escopeta de un Solo CaГұГіn, mediante trueque, saqueo u otra cosa...\n\nLos cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ВЎAsegГәrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_SINGLESHOTGUN_COMPLETE"] = "Supongo que no eres tan estГәpido como pareces. ВЎPero no te creas superior! ВЎMatГ© a mi primer cuervo a los dos aГұos!"

lang["#MISSION_CROWMAN_357"] = "Martillo Emplumado"
lang["#MISSION_CROWMAN_357_DESC"] = "ВЎTГә, mocoso! Tengo un nuevo desafГӯo para ti. Esta vez, quiero que mates un cuervo usando un RevГіlver .357 o un Repetidor de Vaquero, ВЎY NADA MГҒS! ВЎLO SABRГү!"
lang["#MISSION_CROWMAN_357_HINT"] = "Adquiere un RevГіlver .357 o un Repetidor de Vaquero, mediante trueque, saqueo u otra cosa...\n\nLos cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ВЎAsegГәrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_357_COMPLETE"] = "ВҝPor fin terminaste? ВЎTe tomГі bastante tiempo!"
lang["#MISSION_CROWMAN_357_WEP"] = "RevГіlver .357 o Repetidor de Vaquero"

lang["#MISSION_CROWMAN_SERVICERIFLE"] = "Graznido de Metal Completo"
lang["#MISSION_CROWMAN_SERVICERIFLE_DESC"] = "ВЎTГә, mocoso! Tengo un nuevo desafГӯo para ti. Esta vez, quiero que mates un cuervo usando uno de esos rifles de los chicos de la RNC, ВЎY NADA MГҒS! ВЎLO SABRГү!"
lang["#MISSION_CROWMAN_SERVICERIFLE_HINT"] = "Adquiere un Rifle de Servicio, mediante trueque, saqueo u otra cosa...\n\nLos cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ВЎAsegГәrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_SERVICERIFLE_COMPLETE"] = "ВҝPor fin terminaste? ВЎTe tomГі bastante tiempo!"

