lang["#MISSION_CROWMAN_BAZOOKA"] = "CГіmo OdГӯn perdiГі su ojo"
lang["#MISSION_CROWMAN_BAZOOKA_DESC"] = "ВЎTГә, mocoso! Tengo un nuevo desafГӯo para ti. Esta vez, todo lo que quiero es que mates un solo cuervo. AsГӯ es, solo un cuervo, usando un Lanzamisiles. ВЎY NADA MГҒS! ВЎLO SABRГү!"
lang["#MISSION_CROWMAN_BAZOOKA_HINT"] = "Adquiere un Lanzamisiles, mediante trueque, saqueo u otra cosa...\n\nLos cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ВЎAsegГәrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_BAZOOKA_COMPLETE"] = "ВҝPor fin terminaste? ВЎTe tomГі bastante tiempo!"

lang["#MISSION_CROWMAN_CROWBAR"] = "No pretendo entrometerme..."
lang["#MISSION_CROWMAN_CROWBAR_DESC"] = "ВЎTГә, mocoso! ВЎEsta vez te tengo! ВЎTe tengo calado! ВЎNO HAY MANERA de que superes este desafГӯo! Quiero que mates un cuervo. Solo uno mГЎs. Y lo harГЎs usando una palanca. ВЎY NADA MГҒS! ВЎLO SABRГү!"
lang["#MISSION_CROWMAN_CROWBAR_HINT"] = "Adquiere una Palanca, mediante trueque, saqueo u otra cosa...\n\nLos cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores."
lang["#MISSION_CROWMAN_CROWBAR_COMPLETE"] = "EstГЎ bien, ganas. Puedes quedarte con esto. Y con esta escopeta. Iba a ser para mi hijo cuando alcanzara la mayorГӯa de edad. Antes de... que los cuervos se lo llevaran..."

-- DesafГӯo de cantidad

lang["#MISSION_CROWMAN_X10"] = "Control de Plagas"
lang["#MISSION_CROWMAN_X10_DESC"] = "ВЎTГә, mocoso! ВЎLos has visto, Вҝverdad?! ВЎPlaneando, aleteando, lanzando maldiciones en su lengua picuda, y lo peor de todo! ВЎROBANDO MI MAГҚZ! Los cuervos han vuelto, y se han enterado de lo que hiciste. Saben que mataste a uno de los suyos, sin provocaciГіn y sin aliento de nadie mГЎs. ВЎAhora estГЎn robando mi maГӯz en venganza! ВЎTГә causaste esto, ahora lo arreglas!"
lang["#MISSION_CROWMAN_X10_HINT"] = "Los cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ВЎAsegГәrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_X10_COMPLETE"] = "ВҝLos atrapaste a todos? Te tomГі bastante tiempo. ВЎYo podrГӯa haberlo hecho en la mitad de tiempo, si no estuviera ocupado vigilando mi maГӯz!"

lang["#MISSION_CROWMAN_X25"] = "DepredaciГіn"
lang["#MISSION_CROWMAN_X25_DESC"] = "ВЎTГә, mocoso! Apuesto a que te sientes muy orgulloso por el trabajo que hiciste con los cuervos antes, Вҝeh? ВЎPUES NO DEBERГҚAS! ВЎHan vuelto! Lo vi con mis propios ojos, un cuervo bajГі volando y le arrebatГі la comida de las manos a Isaac. Lo mГЎs divertido que he visto en toda la semana. ВЎPero todavГӯa tienes un lГӯo que limpiar! ВЎSal ahГӯ y acaba con el resto!"
lang["#MISSION_CROWMAN_X25_HINT"] = "Los cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ВЎAsegГәrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_X25_COMPLETE"] = "ВҝPor fin terminaste? Ya veremos. Esos cuervos son listos. ВЎPero no mГЎs que yo! ВЎConozco sus trucos!"

lang["#MISSION_CROWMAN_X50"] = "ConCAWflicto Abierto"
lang["#MISSION_CROWMAN_X50_DESC"] = "ВЎTГә, mocoso! PensГ© que te dije que te encargaras del problema de los cuervos. ВҝEl que causaste en primer lugar? ВҝEntonces por quГ© me despertГ© esta maГұana solo para encontrar una bandada entera de cuervos, sentados en mi granero, mirГЎndome con sus pequeГұos ojos de cuentas? ВЎEstГЎn construyendo un ejГ©rcito, NO, UNA FUERZA AГүREA! ВЎTienes que diezmarlos antes de que sea demasiado tarde!"
lang["#MISSION_CROWMAN_X50_HINT"] = "Los cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ВЎAsegГәrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_X50_COMPLETE"] = "ВҝTerminaste? ВЎBien! La mayorГӯa de la gente no habrГӯa necesitado tres intentos para hacerlo, pero la mayorГӯa de la gente no es como tГә."

lang["#MISSION_CROWMAN_X100"] = "Asesinato, a escala macabra"
lang["#MISSION_CROWMAN_X100_DESC"] = "No puedo casi creerlo. AquГӯ estaba yo, seguro de que la Гәltima vez que saliste a mi campo, me dijiste que habГӯas resuelto el problema de los cuervos.\nВҝEl que estГЎn concentrando sus fuerzas en masa? ВҝEL PROBLEMA QUE CAUSASTE EN PRIMER LUGAR! ВҝEntonces por quГ© cuando ese tal Ike, ese excusa de barman, vino a recoger su Гәltimo celemГӯn de mi maГӯz, empezГі a contarme algo que escuchГі de uno de sus parroquianos? Dijo que el chico llegГі tambaleГЎndose desde las ruinas de Fallon, y no paraba de hablar de una flota entera de pГЎjaros negros reunidos al otro lado de las colinas, al oeste. ВЎVe a ello, y hazlo bien esta vez!"
lang["#MISSION_CROWMAN_X100_HINT"] = "Los cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ВЎAsegГәrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_X100_COMPLETE"] = "ВЎMocoso! No descorches el licor de maГӯz todavГӯa. LlГЎmalo reconocimiento de patrones, pero creo que esto es la calma antes de la tormenta..."

lang["#MISSION_CROWMAN_X200"] = "Nunca MГЎs"
lang["#MISSION_CROWMAN_X200_DESC"] = "ВЎTГә, mocoso! Nuestros peores temores se han hecho realidad. Tu completo fracaso en sofocar una simple rencilla con los cuervos ha degenerado en una guerra total entre cuervos y humanos. EnviГ© a Andrew a explorar las lГӯneas enemigas hace 30 minutos y no he tenido noticias suyas desde entonces, temo que ya estГ© muerto. ReГәne toda la municiГіn, estimulantes y drogas que puedas llevar en tus brazos. Si ambos sobrevivimos a esto, ВЎpuede que te perdone por haber creado este problema en primer lugar!"
lang["#MISSION_CROWMAN_X200_HINT"] = "Los cuervos se pueden encontrar volando alrededor del pueblo de Salt Wells y sus alrededores. ВЎAsegГәrate de 'apuntar delante del objetivo' antes de disparar!"
lang["#MISSION_CROWMAN_X200_COMPLETE"] = "ВҝSe... se acabГі? ВҝGanamos? ВЎLo hicimos! ВЎA pesar de todos tus fracasos, los rechazamos!"

